public static void processStagingTableRecord(ccBatchWorkLoad _stagingTable)
{
    if (_stagingTable.dummyValue mod 10 == 0)
    {
        throw error(strFmt('random error for record: %1', _stagingTable.dummyValue));
    }
    //process the data in the record.
    info(strfmt("Value is %1", _stagingTable.dummyValue));
    //sleep(5000);
}
